import { useEffect, useState } from 'react';
import { Plus, Trash2, ShoppingCart, Search, RefreshCw } from 'lucide-react';
import { orderService, userService, productService } from '../services/api';
import { Modal, FormField, ConfirmDialog, DataTable, EmptyState, PageLoader, StatusBadge } from '../components/UI';
import toast from 'react-hot-toast';

// ─── Create Order Modal ────────────────────────────────────
const CreateOrderModal = ({ isOpen, onClose, onSaved }) => {
  const [form, setForm]       = useState({ userId: '', productId: '', quantity: 1 });
  const [users, setUsers]     = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [loadingData, setLoadingData] = useState(true);

  useEffect(() => {
    if (!isOpen) return;
    const load = async () => {
      setLoadingData(true);
      try {
        const [u, p] = await Promise.all([userService.getAll(), productService.getAll()]);
        setUsers(u.data);
        setProducts(p.data);
      } catch { toast.error('Không tải được dữ liệu!'); }
      finally { setLoadingData(false); }
    };
    load();
    setForm({ userId: '', productId: '', quantity: 1 });
  }, [isOpen]);

  const selectedProduct = products.find(p => p.id === parseInt(form.productId));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await orderService.create({
        userId: parseInt(form.userId),
        productId: parseInt(form.productId),
        quantity: parseInt(form.quantity),
      });
      toast.success('Tạo order thành công!');
      onSaved();
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Có lỗi xảy ra!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Tạo Order mới">
      {loadingData ? (
        <div className="flex justify-center py-8"><div className="animate-spin w-6 h-6 border-2 border-brand-400 border-t-transparent rounded-full" /></div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-4">
          <FormField label="Khách hàng" required>
            <select className="input-field" value={form.userId}
              onChange={e => setForm(f => ({ ...f, userId: e.target.value }))} required>
              <option value="">-- Chọn user --</option>
              {users.map(u => <option key={u.id} value={u.id}>{u.name} ({u.email})</option>)}
            </select>
          </FormField>

          <FormField label="Sản phẩm" required>
            <select className="input-field" value={form.productId}
              onChange={e => setForm(f => ({ ...f, productId: e.target.value }))} required>
              <option value="">-- Chọn sản phẩm --</option>
              {products.map(p => (
                <option key={p.id} value={p.id}>
                  {p.name} — {parseFloat(p.price).toLocaleString('vi-VN')}đ (còn {p.stock})
                </option>
              ))}
            </select>
          </FormField>

          <FormField label="Số lượng" required>
            <input type="number" min="1" max={selectedProduct?.stock || 999}
              className="input-field" value={form.quantity}
              onChange={e => setForm(f => ({ ...f, quantity: e.target.value }))} required />
          </FormField>

          {/* Preview tổng tiền */}
          {selectedProduct && form.quantity > 0 && (
            <div className="p-4 bg-brand-600/10 border border-brand-500/20 rounded-xl">
              <p className="text-sm text-slate-400">Thành tiền dự kiến:</p>
              <p className="text-xl font-bold text-brand-400">
                {(parseFloat(selectedProduct.price) * parseInt(form.quantity || 0)).toLocaleString('vi-VN')}đ
              </p>
            </div>
          )}

          <div className="flex gap-3 justify-end pt-2">
            <button type="button" onClick={onClose} className="btn-secondary">Hủy</button>
            <button type="submit" disabled={loading} className="btn-primary">
              {loading ? 'Đang tạo...' : 'Tạo Order'}
            </button>
          </div>
        </form>
      )}
    </Modal>
  );
};

// ─── Update Status Modal ───────────────────────────────────
const StatusModal = ({ isOpen, onClose, onSaved, order }) => {
  const [status, setStatus]   = useState('');
  const [loading, setLoading] = useState(false);
  const statuses = ['Pending', 'Confirmed', 'Cancelled'];

  useEffect(() => { if (order) setStatus(order.status); }, [order]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await orderService.updateStatus(order.id, status);
      toast.success('Cập nhật trạng thái thành công!');
      onSaved();
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Có lỗi xảy ra!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={`Cập nhật trạng thái Order #${order?.id}`} size="sm">
      <form onSubmit={handleSubmit} className="space-y-4">
        <FormField label="Trạng thái">
          <div className="flex flex-col gap-2">
            {statuses.map(s => (
              <label key={s} className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${status === s ? 'border-brand-500 bg-brand-500/10' : 'border-slate-700 hover:border-slate-600'}`}>
                <input type="radio" name="status" value={s} checked={status === s}
                  onChange={() => setStatus(s)} className="accent-brand-500" />
                <StatusBadge status={s} />
              </label>
            ))}
          </div>
        </FormField>
        <div className="flex gap-3 justify-end pt-2">
          <button type="button" onClick={onClose} className="btn-secondary">Hủy</button>
          <button type="submit" disabled={loading} className="btn-primary">
            {loading ? 'Đang lưu...' : 'Cập nhật'}
          </button>
        </div>
      </form>
    </Modal>
  );
};

// ═══════════════════════════════════════════════════════════
// ORDERS PAGE
// ═══════════════════════════════════════════════════════════
export const OrdersPage = () => {
  const [orders, setOrders]     = useState([]);
  const [loading, setLoading]   = useState(true);
  const [search, setSearch]     = useState('');
  const [filterStatus, setFilter] = useState('');
  const [createModal, setCreateModal] = useState(false);
  const [statusModal, setStatusModal] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [deleteId, setDeleteId] = useState(null);
  const [deleting, setDeleting] = useState(false);

  const load = async () => {
    setLoading(true);
    try {
      const res = await orderService.getAll();
      setOrders(res.data);
    } catch {
      toast.error('Không tải được danh sách orders!');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await orderService.delete(deleteId);
      toast.success('Xóa order thành công!');
      setDeleteId(null);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa thất bại!');
    } finally {
      setDeleting(false);
    }
  };

  const handleStatusClick = (order) => { setSelectedOrder(order); setStatusModal(true); };

  const filtered = orders.filter(o => {
    const matchSearch = !search ||
      o.user?.name?.toLowerCase().includes(search.toLowerCase()) ||
      o.product?.name?.toLowerCase().includes(search.toLowerCase()) ||
      String(o.id).includes(search);
    const matchStatus = !filterStatus || o.status === filterStatus;
    return matchSearch && matchStatus;
  });

  if (loading) return <PageLoader />;

  return (
    <div className="space-y-6 animate-slide-up">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-100">Quản lý Orders</h1>
          <p className="text-slate-500 mt-1">{orders.length} đơn hàng trong hệ thống</p>
        </div>
        <div className="flex gap-3">
          <button onClick={load} className="btn-secondary">
            <RefreshCw size={16} /> Làm mới
          </button>
          <button onClick={() => setCreateModal(true)} className="btn-primary">
            <Plus size={18} /> Tạo Order
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="card">
        <div className="flex gap-4 mb-6">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <input className="input-field pl-10" placeholder="Tìm theo ID, tên khách hàng, sản phẩm..."
              value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <select className="input-field w-48" value={filterStatus} onChange={e => setFilter(e.target.value)}>
            <option value="">Tất cả trạng thái</option>
            <option value="Pending">Pending</option>
            <option value="Confirmed">Confirmed</option>
            <option value="Cancelled">Cancelled</option>
          </select>
        </div>

        <DataTable
          headers={['#', 'Khách hàng', 'Sản phẩm', 'SL', 'Tổng tiền', 'Trạng thái', 'Ngày tạo', 'Thao tác']}
          empty={
            <tr><td colSpan={8}>
              <EmptyState icon={ShoppingCart} title="Chưa có order nào" desc="Tạo order đầu tiên để bắt đầu" />
            </td></tr>
          }
        >
          {filtered.map(order => (
            <tr key={order.id} className="table-row">
              <td className="py-3 px-4 text-slate-500 text-sm font-mono">#{order.id}</td>
              <td className="py-3 px-4 text-slate-300 text-sm">{order.user?.name || 'N/A'}</td>
              <td className="py-3 px-4 text-slate-300 text-sm">{order.product?.name || 'N/A'}</td>
              <td className="py-3 px-4 text-slate-400 text-sm text-center">{order.quantity}</td>
              <td className="py-3 px-4 text-slate-200 font-semibold text-sm">
                {parseFloat(order.totalPrice).toLocaleString('vi-VN')}đ
              </td>
              <td className="py-3 px-4">
                <button onClick={() => handleStatusClick(order)} className="hover:opacity-80 transition-opacity">
                  <StatusBadge status={order.status} />
                </button>
              </td>
              <td className="py-3 px-4 text-slate-500 text-sm">
                {new Date(order.createdAt).toLocaleDateString('vi-VN')}
              </td>
              <td className="py-3 px-4">
                <button onClick={() => setDeleteId(order.id)} className="p-1.5 text-slate-400 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all">
                  <Trash2 size={15} />
                </button>
              </td>
            </tr>
          ))}
        </DataTable>
      </div>

      <CreateOrderModal isOpen={createModal} onClose={() => setCreateModal(false)} onSaved={load} />
      <StatusModal isOpen={statusModal} onClose={() => setStatusModal(false)} onSaved={load} order={selectedOrder} />
      <ConfirmDialog
        isOpen={!!deleteId} onClose={() => setDeleteId(null)}
        onConfirm={handleDelete} loading={deleting}
        title="Xóa Order"
        message="Bạn có chắc muốn xóa order này? Hành động này không thể hoàn tác."
      />
    </div>
  );
};
